cd /tmp/sv-eda6187eb99b4244873edd01af9038a6/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null > after-cpm-packages.json && python3 -c "
import json
with open('after-cpm-packages.json') as f:
    after = json.load(f)
# Baseline values we captured earlier
baseline = {
    'Api.csproj': {'Microsoft.AspNetCore.OpenApi': '8.0.24', 'OpenTelemetry.Extensions.Hosting': '1.15.0'},
    'Data.csproj': {'Microsoft.Extensions.DependencyInjection': '9.0.0', 'Microsoft.Extensions.DependencyInjection.Abstractions': '9.0.0'}
}
for proj in after['projects']:
    pname = proj['path'].split('/')[-1]
    for fw in proj['frameworks']:
        for pkg in fw['topLevelPackages']:
            bv = baseline.get(pname, {}).get(pkg['id'])
            status = 'MATCH' if bv == pkg['resolvedVersion'] else f'CHANGED {bv} -> {pkg[\"resolvedVersion\"]}'
            print(f'{pname}: {pkg[\"id\"]} {pkg[\"resolvedVersion\"]} [{status}]')
"

